window.__QUIZ_DATA__=[{"id":"theory>Agricultural Science Practical>2020>1>a","subject":"Agricultural Science Practical","year":"2020","type":"Practical","sub_label":"a","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS","question":"State two uses each of specimens A (HOE) and B(PICK AXE)","images":[],"marking_scheme":"Uses of specimens A (Hoe) and B (Pick axe);    A(Hoe);    Loosening the soil;  Uprooting weeds/weeding;  Harvesting of crops e.g. groundnut and yam;  Making ridges/heaps/mounds/seed bed;  Planting/transplanting of some crops.  B (PickAxe):    Breaking up hard ground/ loosening the soil;  Stumping/uprooting of trees and stones;  For making ridges;  For tilling soil for farm building erection;  Digging hole, pits","marks":"1","difficulty":"1"},{"id":"theory>Agricultural Science Practical>2020>1>b","subject":"Agricultural Science Practical","year":"2020","type":"Practical","sub_label":"b","group":"","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Name four crops that require the use of specimen D (BUDDING KNIFE) during propagation.","images":[],"marking_scheme":"Crops that require the use of specimen D(Budding knife) during propagation:    Mango,  Citrus,  Avocado pear,  Cashew,  Apple,  Cherry,  Rubber,  Cocoa,  Coffee,  Kola,  Walnut,  Plum","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2020>1>c","subject":"Agricultural Science Practical","year":"2020","type":"Practical","sub_label":"c","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS","question":"Name three other tools that could serve the same purpose as specimen E (BURDIZZO).","images":[],"marking_scheme":"Other tools that could serve the same purpose as Specimen E (Burdizzo):    Sharp knife,  Emasculator,  Scalpel,  Hemostat,  Razor blade,  Elastrator,  Forceps,  Pincers.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2020>1>d","subject":"Agricultural Science Practical","year":"2020","type":"Practical","sub_label":"d","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : MAINTENANCE PRACTICES AND PRECAUTIONARY MEASURES","question":"Mention four ways of maintaining specimen A (HOE)  on the farm.","images":[],"marking_scheme":"Ways of maintaining specimen A (Hoe) on the farm:-    Wash and dry/clean after use,  Store in cool, dry place,  Straighten bent blade,  Keep wooden handle away from termite attack,  Replace worn out parts,  Oil/grease metal blade before storage,  Sharpen the blunt blade","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2020>2>a","subject":"Agricultural Science Practical","year":"2020","type":"Practical","sub_label":"a","group":"","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"What is the aim of the experimental set-up F?","images":[],"marking_scheme":"Aim of the experiment set-up F:     Determination of Soil texture by sedimentation/sedimentation experiment","marks":"1","difficulty":"3"},{"id":"theory>Agricultural Science Practical>2020>2>b","subject":"Agricultural Science Practical","year":"2020","type":"Practical","sub_label":"b","group":"","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT~~AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"List three materials that could be used in carrying out the experiment in the set-up F.","images":[],"marking_scheme":"Materials that could be used in carrying out the experiment in the set-up F:    Soil sample,  Measuring cylinder,  Beaker,  Glass jar,  Water,  Glass rod/ stirrer,  Hydrogen peroxide/Calgon","marks":"1","difficulty":"1"},{"id":"theory>Agricultural Science Practical>2020>2>c","subject":"Agricultural Science Practical","year":"2020","type":"Practical","sub_label":"c","group":"","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT~~AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"Outline three steps invo\u0142ved in carrying out the experiment.","images":[],"marking_scheme":"Steps involved in carrying out the experiment:    Put a quantity of soil sample in the measuring cylinder,  Water is added to the soil sample in the measuring cylinder,  Hydrogen peroxide could be added to break soil lumps,  The content in the measuring cylinder is n stirred with a glass rod/shake vigorously,  The content is allowed to settle for some hours.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2020>2>d","subject":"Agricultural Science Practical","year":"2020","type":"Practical","sub_label":"d","group":"","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"Name four soil components observed in the experimental set-up.","images":[],"marking_scheme":"Soil components observed in the experimental set-up:    Coarse sand,  Silt, Water,  Fine sand,  Clay,  Organic matter","marks":"1","difficulty":"1"},{"id":"theory>Agricultural Science Practical>2020>2>e","subject":"Agricultural Science Practical","year":"2020","type":"Practical","sub_label":"e","group":"","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"Draw and label the experimental set-up.","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2020>3>a>i","subject":"Agricultural Science Practical","year":"2020","type":"Practical","sub_label":"i","group":"","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Name the toxic substance found in specimen G (FRESH CASSAVA TUBER).","images":[],"marking_scheme":"Name of toxic substance found in specimen G (Fresh cassava tuber):    - Hydrogen cyanide/cyanide/prussic acid/Hydrocyanic.","marks":"1","difficulty":"1"},{"id":"theory>Agricultural Science Practical>2020>3>a>ii","subject":"Agricultural Science Practical","year":"2020","type":"Practical","sub_label":"ii","group":"","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Suggest four ways of removing the toxic substance named in (a)(i).","images":[],"marking_scheme":"Ways of removing hydrogen cyanide in fresh cassava tubers:    Grating the tubers and squeezing out the water under pressure for few days  Soaking the tubers in water for some days/ fermentation,  Drying the soaked tubers in water for some days/fermentation,  Drying the soaked tubers in the sun,  Boiling/cooking the tubers,  Frying.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2020>3>b","subject":"Agricultural Science Practical","year":"2020","type":"Practical","sub_label":"b","group":"","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"State two uses each of specimens I (ONION BULBS) and J (PEPPER FRUITS).","images":[],"marking_scheme":"Uses of specimen I (Onion bulbs) and J (Pepper fruits):    I (Onion bulbs);    Sources of vitamins A and C.  For flavouring food,  Medicinal uses,  Source of volatile oil,  Eaten as food,  Antioxidant,  Boost digestion,  Nourish the skin,   To repel snakes around the home.  J(Pepper fruits):    Spice for food,  Insect repellant in stored produce,  Medicinal uses,  Used as yolk colourant,  Source of antioxidant (piperine),  Used in tear gas to disperse crowds/ as pepper spray.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2020>3>c","subject":"Agricultural Science Practical","year":"2020","type":"Practical","sub_label":"c","group":"","topic":"CROP PROTECTION : PESTS OF CROPS","question":"List four pests of specimen I.","images":[],"marking_scheme":"Pest of specimen L (Onion bulbs):    Grasshopper.  Cricket,  Cockroach,  Monkey,  Thrips,  Rat/Rodents,  Maggot.   Eelworm","marks":"1","difficulty":"1"},{"id":"theory>Agricultural Science Practical>2020>3>d","subject":"Agricultural Science Practical","year":"2020","type":"Practical","sub_label":"d","group":"","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"Name two groups of crops to which specimens I and J belong based on their uses.","images":[],"marking_scheme":"Group of crops to which specimens I(Onion bulbs) and J (Pepper fruits) belong based on their uses;    Spices  Vegetables","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2020>4>a","subject":"Agricultural Science Practical","year":"2020","type":"Practical","sub_label":"a","group":"","topic":"ANIMAL PRODUCTION : AQUACULTURE","question":"Give three reasons for stocking K (TILAPIA) and L (CATFISH) together in a pond.","images":[],"marking_scheme":"Reasons for stocking specimens K(Tilapia) and L(Catfish) together in a pond:    Tilapia and catfish can co-exist successfully in ponds,  Tilapia and catfish have different feeding habits,  Tilapia is herbivorous while catfish is carnivorous,  Tilapia is a surface feeder while catfish is a bottom feeder,  Catfish checks/controls the population of tilapia which multiplies at a very fast rate and could overpopulate the pond,  Optimizing farmers' income/ harvest,  To ensure adequate utilization of the pond's space.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2020>4>b","subject":"Agricultural Science Practical","year":"2020","type":"Practical","sub_label":"b","group":"","topic":"ANIMAL PRODUCTION : AQUACULTURE","question":"List four fishing gears used for harvesting specimens K and L in a pond","images":[],"marking_scheme":"Fishing gears used for harvesting specimens K (Tilapia) and L (Catfish) in a pond:    Hook and line,  Fish trap  Fishing gourd  Use of nets e.g seine net, drag net, scoop net, cast net,  fishing spear/harpoons  basket","marks":"1","difficulty":"1"},{"id":"theory>Agricultural Science Practical>2020>4>c","subject":"Agricultural Science Practical","year":"2020","type":"Practical","sub_label":"c","group":"","topic":"ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS","question":"Name four products that could be made from specimen M(MILK)","images":[],"marking_scheme":"Products that could be made from specimen M (milk):    Cheese,  Yoghurt,  Skimmed milk/ condensed/ can milk,  Casein,  Butter scotch,  Butter,  Ice cream,  Whey,  Milk Candy.","marks":"1","difficulty":"1"},{"id":"theory>Agricultural Science Practical>2020>4>d","subject":"Agricultural Science Practical","year":"2020","type":"Practical","sub_label":"d","group":"","topic":"ANIMAL PRODUCTION : AQUACULTURE","question":"State four reasons for adding specimen N (LIME)  to the pond in which specimens K and L are stocked.","images":[],"marking_scheme":"Reasons for adding specimen N (Lime) to the pond in which specimens K(Tilapia) and L(Catfish) are stocked:    Reduces pond acidity,  Reduces pond turbidity,  Makes fertilizers to be effective,  Supplies calcium for fish bone development,  Destroys leeches on tilapia and catfish skin,  To seal pores and prevent water loss,  To increase the availability of nutrient such as phosphorus in ponds with acid soil,  It reduces free carbon dioxide in pond water,  To encourage the growth of planktons.","marks":"1","difficulty":"2"}];